#include <iostream>
#include <stdexcept>
using namespace std;

double divide(double a, double b) {
    if (b == 0) throw runtime_error("Division by zero!");
    return a / b;
}

int main() {
    try {
        cout << divide(10, 2)  << endl;
        cout << divide(10, 0)  << endl;  // throws!
        cout << "Never reached" << endl;
    } catch (const runtime_error& e) {
        cout << "Error: " << e.what() << endl;
    }

    cout << "Program continues." << endl;
    return 0;
}

#include <iostream>
#include <stdexcept>
#include <vector>
using namespace std;

void riskyOperation(int choice) {
    switch (choice) {
        case 1: throw runtime_error("Runtime problem");
        case 2: throw invalid_argument("Bad argument");
        case 3: throw out_of_range("Index too large");
        default: break;
    }
}

int main() {
    for (int i = 0; i <= 3; i++) {
        try {
            riskyOperation(i);
            cout << "Success for " << i << endl;
        } catch (const invalid_argument& e) {
            cout << "Invalid arg: " << e.what() << endl;
        } catch (const out_of_range& e) {
            cout << "Out of range: " << e.what() << endl;
        } catch (const runtime_error& e) {
            cout << "Runtime error: " << e.what() << endl;
        } catch (...) {
            cout << "Unknown error" << endl;
        }
    }
    return 0;
}

