Inherit from `std::exception` or its subclasses to create domain-specific exceptions:

```cpp
class DatabaseError : public runtime_error {
    int errorCode;
public:
    DatabaseError(string msg, int code)
        : runtime_error(msg), errorCode(code) {}
    int getCode() const { return errorCode; }
};
```

