#include <iostream>
#include <stdexcept>
using namespace std;

class InsufficientFundsException : public runtime_error {
    double shortfall;
public:
    InsufficientFundsException(double shortfall)
        : runtime_error("Insufficient funds. Shortfall: $" + to_string(shortfall)),
          shortfall(shortfall) {}

    double getShortfall() const { return shortfall; }
};

class BankAccount {
    double balance;
public:
    BankAccount(double b) : balance(b) {}
    void withdraw(double amount) {
        if (amount > balance)
            throw InsufficientFundsException(amount - balance);
        balance -= amount;
    }
    double getBalance() const { return balance; }
};

int main() {
    BankAccount acc(100.0);
    try {
        acc.withdraw(60);
        cout << "Balance: $" << acc.getBalance() << endl;
        acc.withdraw(80);  // throws!
    } catch (const InsufficientFundsException& e) {
        cout << e.what() << endl;
        cout << "Shortfall: $" << e.getShortfall() << endl;
    }
    return 0;
}

#include <iostream>
#include <stdexcept>
using namespace std;

int safeAdd(int a, int b) noexcept {
    return a + b;  // never throws
}

conditional noexcept — only noexcept if T's move is noexcept:
template <typename T>
void swap(T& a, T& b) noexcept {
    T temp = move(a);
    a = move(b);
    b = move(temp);
}

int main() {
    cout << safeAdd(3, 4) << endl;

    int x = 10, y = 20;
    swap(x, y);
    cout << x << " " << y << endl;

    // Check if noexcept:
    cout << boolalpha << noexcept(safeAdd(1, 2)) << endl;

    return 0;
}

#include <iostream>
#include <memory>
#include <stdexcept>
using namespace std;

class Lock {
public:
    Lock()  { cout << "Lock acquired" << endl; }
    ~Lock() { cout << "Lock released" << endl; }  // ALWAYS runs!
};

void riskyWork() {
    Lock l;  // acquired here
    cout << "Working..." << endl;
    throw runtime_error("Something went wrong!");
    cout << "Never reached" << endl;
}  // Lock destructor runs here — even during exception!

int main() {
    try {
        riskyWork();
    } catch (const runtime_error& e) {
        cout << "Caught: " << e.what() << endl;
    }
    cout << "Done." << endl;
    return 0;
}
